+namespace sv_4c505d8b48a84a71ac5f812db8fdf1de.Services;
+
+/// <summary>
+/// Scoped service that holds the currently selected warehouse for a single circuit (user session).
+/// Raises <see cref="OnChange"/> so any subscribed component can re-render when the selection changes.
+/// </summary>
+public sealed class WarehouseStateService
+{
+    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
+    [
+        ("WH-A", "Warehouse A"),
+        ("WH-B", "Warehouse B"),
+        ("WH-C", "Warehouse C"),
+    ];
+
+    private string _currentWarehouseId = AvailableWarehouses[0].Id;
+
+    public string CurrentWarehouseId => _currentWarehouseId;
+
+    public string CurrentWarehouseName =>
+        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name ?? _currentWarehouseId;
+
