namespace sv_4c505d8b48a84a71ac5f812db8fdf1de.Services;

/// <summary>
/// Scoped service that tracks the latest low-stock alert count for the active warehouse.
/// Components call <see cref="RefreshAsync"/> (typically from a polling timer) and all
/// subscribers receive the result through <see cref="OnAlertCountChanged"/>.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();
    private int _lastCount;

    public int LastCount => _lastCount;

    /// <summary>Raised after every successful refresh so all subscribed components can re-render.</summary>
    public event Action? OnAlertCountChanged;

    /// <summary>Simulates a database query returning low-stock item count for the given warehouse.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate variable latency and a random count between 0 and 15.
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches the latest count and notifies all subscribers.
    /// Designed to be called from a single polling source; the notification fans out to every component.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        _lastCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

