@using sv_4c505d8b48a84a71ac5f812db8fdf1de.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" style="width:200px"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_4c505d8b48a84a71ac5f812db8fdf1de.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.LastCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.LastCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnCountChanged;
    }

    private void OnCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnCountChanged;
    }
}

